#include <iostream>
#include <string>
#include <vector>

class Patient {
    std::string m_name;
public:
    Patient(std::string name) : m_name{name} {}
    const std::string& getName() const { return m_name; }
};

class Doctor {
    std::string m_name;
    std::vector<Patient*> m_patients{};
public:
    Doctor(std::string name) : m_name{name} {}
    void addPatient(Patient* p) { m_patients.push_back(p); }
    const std::string& getName() const { return m_name; }
    const std::vector<Patient*>& getPatients() const { return m_patients; }
};

int main() {
    int d{};
    std::cin >> d;
    std::vector<Doctor> doctors;
    for (int i{0}; i < d; ++i) {
        std::string name;
        std::cin >> name;
        doctors.push_back(Doctor{name});
    }

    int p{};
    std::cin >> p;
    std::vector<Patient> patients;
    for (int i{0}; i < p; ++i) {
        std::string name;
        std::cin >> name;
        patients.push_back(Patient{name});
    }

    int a{};
    std::cin >> a;
    for (int i{0}; i < a; ++i) {
        int di{}, pi{};
        std::cin >> di >> pi;
        doctors[di].addPatient(&patients[pi]);
    }

    int q{};
    std::cin >> q;

    std::cout << doctors[q].getName() << ':';
    for (auto* pat : doctors[q].getPatients()) {
        std::cout << ' ' << pat->getName();
    }
    std::cout << '\n';

    return 0;
}

