#include <iostream>
#include <string>
#include <vector>

class Course;

class Student {
    std::string m_name;
    std::vector<Course*> m_courses{};
public:
    Student(std::string name) : m_name{name} {}
    const std::string& getName() const { return m_name; }
    void addCourse(Course* c) { m_courses.push_back(c); }
};

class Course {
    std::string m_name;
    std::vector<Student*> m_students{};
public:
    Course(std::string name) : m_name{name} {}
    const std::string& getName() const { return m_name; }
    void addStudent(Student* s) { m_students.push_back(s); }
    const std::vector<Student*>& getStudents() const { return m_students; }
};

void enroll(Student& s, Course& c) {
    s.addCourse(&c);
    c.addStudent(&s);
}

int main() {
    int sc{};
    std::cin >> sc;
    std::vector<Student> students;
    for (int i{0}; i < sc; ++i) {
        std::string name;
        std::cin >> name;
        students.push_back(Student{name});
    }

    int cc{};
    std::cin >> cc;
    std::vector<Course> courses;
    for (int i{0}; i < cc; ++i) {
        std::string name;
        std::cin >> name;
        courses.push_back(Course{name});
    }

    int e{};
    std::cin >> e;
    for (int i{0}; i < e; ++i) {
        int si{}, ci{};
        std::cin >> si >> ci;
        enroll(students[si], courses[ci]);
    }

    int q{};
    std::cin >> q;

    const auto& enrolled{ courses[q].getStudents() };
    std::cout << courses[q].getName() << ": " << enrolled.size();
    for (auto* st : enrolled) {
        std::cout << ' ' << st->getName();
    }
    std::cout << '\n';

    return 0;
}
